const pruneActivityEvents = `-- name: PruneActivityEvents :exec
DELETE FROM activity_event
WHERE id IN (
    SELECT id FROM activity_event
    ORDER BY id DESC
    LIMIT -1 OFFSET ?
)
`

// Retain only the newest rows globally; bounded diagnostic history like
// node_run. The id primary key both orders and breaks ties exactly.
func (q *Queries) PruneActivityEvents(ctx context.Context, offset int64) error {
	_, err := q.db.ExecContext(ctx, pruneActivityEvents, offset)
	return err
}

const pruneNodeRuns = `-- name: PruneNodeRuns :exec
DELETE FROM node_run
WHERE rowid IN (
    SELECT rowid FROM node_run
    ORDER BY ended_at DESC, rowid DESC
    LIMIT -1 OFFSET ?
)
`

// Retain the newest rows globally. rowid breaks same-nanosecond ties, so the
// limit is exact even when a fast batch stamps equal ended_at values.
func (q *Queries) PruneNodeRuns(ctx context.Context, offset int64) error {
	_, err := q.db.ExecContext(ctx, pruneNodeRuns, offset)
	return err
}

const pruneTerminalJobs = `-- name: PruneTerminalJobs :exec
DELETE FROM job
WHERE id IN (
    SELECT id FROM job
    WHERE status IN ('done', 'failed')
    ORDER BY id DESC
    LIMIT -1 OFFSET ?
)
`

// Never remove active jobs: only terminal done/failed history is bounded
// (mirrors PruneTerminalOutputCommands).
func (q *Queries) PruneTerminalJobs(ctx context.Context, offset int64) error {
	_, err := q.db.ExecContext(ctx, pruneTerminalJobs, offset)
	return err
}

const pruneTerminalOutputCommands = `-- name: PruneTerminalOutputCommands :exec
DELETE FROM output_command
WHERE id IN (
    SELECT id FROM output_command
    WHERE status IN ('done', 'failed')
    ORDER BY id DESC
    LIMIT -1 OFFSET ?
)
`

// Never remove active commands: only terminal done/failed history is bounded.
func (q *Queries) PruneTerminalOutputCommands(ctx context.Context, offset int64) error {
	_, err := q.db.ExecContext(ctx, pruneTerminalOutputCommands, offset)
	return err
}

const readEventsFrom = `-- name: ReadEventsFrom :many
SELECT "offset", topic, "key", payload, snapshot, source_kind, source_scope, occurrence_key, created_at FROM event_log
WHERE "offset" > ?
ORDER BY "offset" ASC
LIMIT ?
`

type ReadEventsFromParams struct {
	Offset int64 `json:"offset"`
	Limit  int64 `json:"limit"`
}

func (q *Queries) ReadEventsFrom(ctx context.Context, arg ReadEventsFromParams) ([]EventLog, error) {
	rows, err := q.db.QueryContext(ctx, readEventsFrom, arg.Offset, arg.Limit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []EventLog{}
	for rows.Next() {
		var i EventLog
		if err := rows.Scan(
			&i.Offset,
			&i.Topic,
			&i.Key,
			&i.Payload,
			&i.Snapshot,
			&i.SourceKind,
			&i.SourceScope,
			&i.OccurrenceKey,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

